use bevy::prelude::*;
use bevy::render::render_resource::{AsBindGroup, ShaderType};
use bevy::shader::ShaderRef;

#[repr(u32)]
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum FxKind {
    Fireball = 0,
    SmokePuff = 1,
    BlackSmoke = 2,
    MuzzleFlash = 3,
    SparkBurst = 4,
    Tracer = 5,
}

#[derive(Clone, Copy, ShaderType, Debug)]
pub struct BillboardParams {
    pub color: Vec4,     // base tint incl. alpha multiplier
    pub spawn_time: f32, // globals.time at spawn
    pub lifetime: f32,   // seconds
    pub start_radius: f32,
    pub end_radius: f32, // for expanding fireball/smoke
    pub seed: f32,       // per-instance noise offset
    pub kind: u32,       // FxKind
    pub _pad: f32,
}

// Additive transparency material (used for glowy effects)
#[derive(Asset, TypePath, AsBindGroup, Clone, Debug)]
pub struct AdditiveFxMaterial {
    #[uniform(0)]
    pub params: BillboardParams,
}

impl Material for AdditiveFxMaterial {
    fn fragment_shader() -> ShaderRef {
        "embedded://demo_resolution_selector_web_bevy/plugins/visual_fx/billboard_fx.wgsl".into()
    }
    fn vertex_shader() -> ShaderRef {
        "embedded://demo_resolution_selector_web_bevy/plugins/visual_fx/billboard_fx.wgsl".into()
    }
    fn alpha_mode(&self) -> AlphaMode {
        AlphaMode::Add
    }
    fn enable_prepass() -> bool {
        false
    }
    fn enable_shadows() -> bool {
        false
    }
    fn specialize(
        _pipeline: &bevy::pbr::MaterialPipeline,
        descriptor: &mut bevy::render::render_resource::RenderPipelineDescriptor,
        _layout: &bevy::render::mesh::MeshVertexBufferLayoutRef,
        _key: bevy::pbr::MaterialPipelineKey<Self>,
    ) -> Result<(), bevy::render::render_resource::SpecializedMeshPipelineError> {
        descriptor.primitive.cull_mode = None;
        Ok(())
    }
}

// Alpha blending transparency material (used for smoke effects)
#[derive(Asset, TypePath, AsBindGroup, Clone, Debug)]
pub struct BlendFxMaterial {
    #[uniform(0)]
    pub params: BillboardParams,
}

impl Material for BlendFxMaterial {
    fn fragment_shader() -> ShaderRef {
        "embedded://demo_resolution_selector_web_bevy/plugins/visual_fx/billboard_fx.wgsl".into()
    }
    fn vertex_shader() -> ShaderRef {
        "embedded://demo_resolution_selector_web_bevy/plugins/visual_fx/billboard_fx.wgsl".into()
    }
    fn alpha_mode(&self) -> AlphaMode {
        AlphaMode::Blend
    }
    fn enable_prepass() -> bool {
        false
    }
    fn enable_shadows() -> bool {
        false
    }
    fn specialize(
        _pipeline: &bevy::pbr::MaterialPipeline,
        descriptor: &mut bevy::render::render_resource::RenderPipelineDescriptor,
        _layout: &bevy::render::mesh::MeshVertexBufferLayoutRef,
        _key: bevy::pbr::MaterialPipelineKey<Self>,
    ) -> Result<(), bevy::render::render_resource::SpecializedMeshPipelineError> {
        descriptor.primitive.cull_mode = None;
        Ok(())
    }
}

use bevy::asset::embedded_asset;
use bevy::prelude::*;
use bevy_egui::EguiPrimaryContextPass;

pub mod car_explosion;
pub mod gun_fx;
pub mod materials;
pub mod settings;
pub mod smoke_emitter;
pub mod spawn;
pub mod ui;

pub use car_explosion::CarExplosionEvent;
pub use gun_fx::GunFxEvent;
pub use smoke_emitter::SmokeEmitter;

use car_explosion::{ExplosionFlashes, car_explosion_observer, draw_explosion_flashes};
use gun_fx::{GunFxCounter, gun_fx_observer, tick_gun_smoke_emitters};
use materials::{AdditiveFxMaterial, BlendFxMaterial};
use settings::VfxSettings;
use smoke_emitter::tick_smoke_emitters;
use spawn::{despawn_expired_fx, setup_vfx_meshes, tick_vfx_drift};
use ui::vfx_controls_window;

pub mod demo;

pub struct VisualFXPlugin;

impl Plugin for VisualFXPlugin {
    fn build(&self, app: &mut App) {
        embedded_asset!(app, "billboard_fx.wgsl");

        app.init_resource::<VfxSettings>()
            .init_resource::<ExplosionFlashes>()
            .init_resource::<GunFxCounter>()
            .add_plugins(MaterialPlugin::<AdditiveFxMaterial>::default())
            .add_plugins(MaterialPlugin::<BlendFxMaterial>::default())
            .add_observer(car_explosion_observer)
            .add_observer(gun_fx_observer)
            .add_systems(Startup, setup_vfx_meshes)
            .add_systems(
                Update,
                (
                    despawn_expired_fx,
                    tick_vfx_drift,
                    tick_smoke_emitters,
                    tick_gun_smoke_emitters,
                    draw_explosion_flashes,
                ),
            );

        #[cfg(debug_assertions)]
        app.add_systems(Update, debug_spawn_fireball_on_keypress);

        app.add_systems(EguiPrimaryContextPass, vfx_controls_window);
    }
}

fn debug_spawn_fireball_on_keypress(
    mut commands: Commands,
    keys: Res<ButtonInput<KeyCode>>,
    time: Res<Time>,
    meshes: Option<Res<spawn::VfxMeshes>>,
    mut additive_mats: ResMut<Assets<AdditiveFxMaterial>>,
) {
    if keys.just_pressed(KeyCode::KeyV) {
        if let Some(meshes) = meshes {
            info!("Spawning validation fireball at origin!");
            let now = time.elapsed_secs();
            let params = materials::BillboardParams {
                color: Vec4::new(1.0, 0.6, 0.1, 1.0),
                spawn_time: now,
                lifetime: 1.5,
                start_radius: 1.0,
                end_radius: 4.0,
                seed: rand::random::<f32>(),
                kind: materials::FxKind::Fireball as u32,
                _pad: 0.0,
            };
            spawn::spawn_additive_billboard_fx(
                &mut commands,
                &mut additive_mats,
                &meshes,
                &time,
                Vec3::new(0.0, 1.0, 0.0),
                params,
            );
        }
    }
}

use super::settings::VfxSettings;
use crate::ui_egui::UiState;
use bevy::prelude::*;
use bevy_egui::{EguiContexts, egui};

pub fn vfx_controls_window(
    mut contexts: EguiContexts,
    mut ui_state: ResMut<UiState>,
    mut s: ResMut<VfxSettings>,
) {
    let Ok(ctx) = contexts.ctx_mut() else {
        return;
    };
    if !ui_state.show_vfx_shaders {
        return;
    }

    egui::Window::new("VFX Shaders Controls")
        .open(&mut ui_state.show_vfx_shaders)
        .default_open(true)
        .show(ctx, |ui| {
            ui.collapsing("Car explosion", |ui| {
                ui.checkbox(&mut s.car_fireball, "Fireball");
                ui.checkbox(&mut s.car_smoke, "Explosion smoke");
                ui.checkbox(&mut s.car_black_smoke, "Wreck black smoke");
                ui.checkbox(&mut s.car_explosion_gizmos, "Damage gizmos (3 spheres)");
                ui.checkbox(&mut s.disabled_car_gizmos, "Wreck warning sphere (green)");
                ui.add(
                    egui::Slider::new(&mut s.fireball_lifetime, 0.1..=3.0)
                        .text("Fireball lifetime"),
                );
                ui.add(
                    egui::Slider::new(&mut s.fireball_radius, 1.0..=12.0).text("Fireball radius"),
                );
                ui.add(egui::Slider::new(&mut s.smoke_lifetime, 0.5..=5.0).text("Smoke lifetime"));
                ui.add(egui::Slider::new(&mut s.smoke_opacity, 0.0..=1.0).text("Smoke opacity"));
            });

            ui.collapsing("Gun", |ui| {
                ui.checkbox(&mut s.gun_gizmos, "Gizmos (alpha 0.3)");
                ui.checkbox(&mut s.gun_tracer, "Tracer shader");
                ui.checkbox(&mut s.gun_hit_sparks, "Hit spark burst");
                ui.checkbox(&mut s.gun_muzzle_flash, "Muzzle flash");
                ui.checkbox(&mut s.gun_muzzle_smoke, "Muzzle smoke");
                ui.add(egui::Slider::new(&mut s.tracer_width, 0.01..=0.3).text("Tracer width"));
                ui.add(egui::Slider::new(&mut s.spark_count_scale, 0.1..=3.0).text("Spark scale"));
                ui.add(
                    egui::Slider::new(&mut s.muzzle_smoke_every, 1..=10)
                        .text("Smoke every N shots"),
                );
            });
        });
}

use super::materials::{AdditiveFxMaterial, BillboardParams, BlendFxMaterial};
use bevy::camera::visibility::NoFrustumCulling;
use bevy::prelude::*;

#[derive(Component, Debug)]
pub struct VfxLifetime {
    pub despawn_at: f64, // seconds, absolute time elapsed
}

#[derive(Component, Debug)]
pub struct VfxDrift {
    pub velocity: Vec3,
}

#[derive(Resource, Debug)]
pub struct VfxMeshes {
    pub quad: Handle<Mesh>,
}

pub fn spawn_additive_billboard_fx(
    commands: &mut Commands,
    mats: &mut Assets<AdditiveFxMaterial>,
    meshes: &VfxMeshes,
    time: &Time,
    pos: Vec3,
    params: BillboardParams,
) -> Entity {
    let despawn_at = time.elapsed_secs_f64() + params.lifetime as f64 + 0.05;
    let mat = mats.add(AdditiveFxMaterial { params });
    commands
        .spawn((
            Mesh3d(meshes.quad.clone()),
            MeshMaterial3d(mat),
            Transform::from_translation(pos),
            // The vertex shader expands the 1x1 quad up to `radius` around the center,
            // well beyond the mesh AABB, so disable frustum culling to keep it from
            // popping out of view near the screen edges.
            NoFrustumCulling,
            VfxLifetime { despawn_at },
        ))
        .id()
}

pub fn spawn_blend_billboard_fx(
    commands: &mut Commands,
    mats: &mut Assets<BlendFxMaterial>,
    meshes: &VfxMeshes,
    time: &Time,
    pos: Vec3,
    params: BillboardParams,
) -> Entity {
    let despawn_at = time.elapsed_secs_f64() + params.lifetime as f64 + 0.05;
    let mat = mats.add(BlendFxMaterial { params });
    commands
        .spawn((
            Mesh3d(meshes.quad.clone()),
            MeshMaterial3d(mat),
            Transform::from_translation(pos),
            // See note in spawn_additive_billboard_fx: the shader expands past the mesh AABB.
            NoFrustumCulling,
            VfxLifetime { despawn_at },
        ))
        .id()
}

pub fn despawn_expired_fx(
    mut commands: Commands,
    time: Res<Time>,
    q: Query<(Entity, &VfxLifetime)>,
) {
    let now = time.elapsed_secs_f64();
    for (e, l) in &q {
        if now >= l.despawn_at {
            if let Ok(mut c) = commands.get_entity(e) {
                c.despawn();
            }
        }
    }
}

pub fn tick_vfx_drift(time: Res<Time>, mut q: Query<(&mut Transform, &VfxDrift)>) {
    let dt = time.delta_secs();
    for (mut tf, drift) in &mut q {
        tf.translation += drift.velocity * dt;
    }
}

pub fn setup_vfx_meshes(mut commands: Commands, mut meshes: ResMut<Assets<Mesh>>) {
    // Create a 1x1 quad in XY plane, centered at 0,0
    let quad = Rectangle::new(1.0, 1.0);
    let handle = meshes.add(quad);
    commands.insert_resource(VfxMeshes { quad: handle });
}

#import bevy_pbr::mesh_functions::get_world_from_local
#import bevy_pbr::mesh_view_bindings::{view, globals}

struct Params {
    color: vec4<f32>,
    spawn_time: f32,
    lifetime: f32,
    start_radius: f32,
    end_radius: f32,
    seed: f32,
    kind: u32,
    _pad: f32,
};
@group(#{MATERIAL_BIND_GROUP}) @binding(0) var<uniform> P: Params;

struct VOut {
    @builtin(position) clip: vec4<f32>,
    @location(0) uv: vec2<f32>,
};

@vertex
fn vertex(@location(0) pos: vec3<f32>,
          @builtin(instance_index) inst: u32) -> VOut {
    // Entity translation = column 3 of the model matrix.
    let model = get_world_from_local(inst);
    let center = model[3].xyz;

    let age = clamp((globals.time - P.spawn_time) / P.lifetime, 0.0, 1.0);
    var world: vec3<f32>;

    if (P.kind == 5u) {
        // Tracer: stretched screen-facing ribbon from muzzle to impact.
        // model[3].xyz is world muzzle, model[0].xyz is impact vector.
        let a = model[3].xyz;
        let beam = model[0].xyz;
        let t = pos.x + 0.5; // pos.x ∈ [-0.5, 0.5] -> t ∈ [0, 1]
        let point = a + beam * t;

        let cam = view.world_position - point;
        let beam_dir = normalize(beam);
        var lateral = normalize(cross(beam_dir, cam));
        if (!(dot(lateral, lateral) > 0.0)) { lateral = view.world_from_view[1].xyz; } // parallel guard

        // Constant screen-ish width: scale by distance so the ribbon stays visible at range
        let dist = length(cam);
        let radius = mix(P.start_radius, P.end_radius, age);
        let half_w = max(radius, 0.0025 * dist);
        world = point + lateral * (pos.y * 2.0 * half_w);
    } else {
        // Standard camera-facing billboard
        let radius = mix(P.start_radius, P.end_radius, age);
        let right = view.world_from_view[0].xyz;
        let up    = view.world_from_view[1].xyz;
        world = center + (right * pos.x + up * pos.y) * radius;
    }

    var out: VOut;
    out.clip = view.clip_from_world * vec4<f32>(world, 1.0);
    if (P.kind == 5u) {
        out.uv = vec2<f32>(pos.x + 0.5, pos.y * 2.0);
    } else {
        out.uv = pos.xy * 2.0; // quad is 1x1 -> uv in [-1,1]
    }
    return out;
}

// cheap hash noise (no textures)
fn hash2(p: vec2<f32>) -> f32 {
    return fract(sin(dot(p, vec2<f32>(127.1, 311.7))) * 43758.5453);
}
fn vnoise(p: vec2<f32>) -> f32 {
    let i = floor(p); let f = fract(p);
    let a = hash2(i); let b = hash2(i + vec2(1.0, 0.0));
    let c = hash2(i + vec2(0.0, 1.0)); let d = hash2(i + vec2(1.0, 1.0));
    let u = f * f * (3.0 - 2.0 * f);
    return mix(mix(a, b, u.x), mix(c, d, u.x), u.y);
}
fn fbm(p: vec2<f32>) -> f32 {
    return 0.5 * vnoise(p) + 0.25 * vnoise(p * 2.03) + 0.125 * vnoise(p * 4.01);
}

@fragment
fn fragment(in: VOut) -> @location(0) vec4<f32> {
    let age = clamp((globals.time - P.spawn_time) / P.lifetime, 0.0, 1.0);
    let r = length(in.uv);                    // 0 center -> ~1.4 corner
    let disk = smoothstep(1.0, 0.0, r);       // soft round mask
    if (disk <= 0.001) { discard; }

    let n = fbm(in.uv * 3.0 + vec2(P.seed, -age * 2.0));

    var rgb = P.color.rgb;
    var alpha = P.color.a;

    switch P.kind {
        case 0u: { // Fireball: hot core -> orange -> fade, turbulent edge
            let heat = disk * (0.6 + 0.4 * n);
            rgb = mix(vec3(1.0, 0.3, 0.0), vec3(1.0, 0.95, 0.4), heat);
            alpha = heat * (1.0 - age) * P.color.a;
        }
        case 1u, 2u: { // Smoke (light or black): billowy, fade in then out
            let puff = disk * (0.6 + 0.4 * n);
            let fade = smoothstep(0.0, 0.08, age) * (1.0 - age); // faster fade-in
            alpha = puff * fade * P.color.a;
        }
        case 3u: { // Muzzle flash: sharp star, very short
            let star = pow(disk, 2.0) * (0.7 + 0.3 * n);
            alpha = star * (1.0 - age) * P.color.a;
        }
        case 4u: { // Spark burst: radial streaks
            let ang = atan2(in.uv.y, in.uv.x);
            let streak = pow(abs(sin(ang * 9.0 + P.seed * 6.28)), 8.0);
            alpha = streak * (1.0 - r) * (1.0 - age) * P.color.a;
        }
        case 5u: { // Tracer: hot core, soft lateral falloff, fade along life
            let edge = smoothstep(1.0, 0.0, abs(in.uv.y));  // 1 at core → 0 at edge
            let core = pow(edge, 4.0);                       // tight bright center
            rgb = mix(P.color.rgb, vec3(1.0), core);         // whiten the core
            alpha = (0.5 * edge + 0.6 * core) * (1.0 - age) * P.color.a;
        }
        default: {}
    }

    return vec4<f32>(rgb, clamp(alpha, 0.0, 1.0));
}

